// Split the due-slots array into N items (one per slot).
const arr = $('Get Due Slots').first().json.data.slots || [];
if (arr.length === 0) {
  // No due slots — short-circuit gracefully (Aggregate sees zero items).
  return [];
}
return arr.map(s => ({ json: {
  slot_id: s.slot_id,
  business_id: s.business_id,
  platform: s.platform,
  caption: s.caption,
  hashtags: s.hashtags || [],
  asset_url: s.asset_url || null,
  scheduled_at: s.scheduled_at || null,
  // exact payload WF-PUBLISH expects
  publishPayload: {
    slot_id: s.slot_id,
    business_id: s.business_id,
    platform: s.platform,
    caption: s.caption,
    hashtags: s.hashtags || [],
    asset_url: s.asset_url || null
  }
}}));

// Aggregate publish results from all calls.
const results = $input.all();
const jobs = $('Prepare Publish Jobs').all();

const items = results.map((r, i) => {
  const job = jobs[i] ? jobs[i].json : {};
  return {
    slot_id: job.slot_id,
    platform: job.platform,
    publish_success: r.json.success === true,
    platform_post_id: r.json.platform_post_id || null,
    permalink: r.json.permalink || null,
    published_at: r.json.published_at || null,
    status: r.json.status || 'unknown'
  };
});

const successes = items.filter(i => i.publish_success).length;
const failures = items.length - successes;

return [{ json: {
  success: true,
  cron: 'publish_due_content',
  ran_at: new Date().toISOString(),
  due_slots_found: items.length,
  published: successes,
  failed: failures,
  items: items
}}];
